package main

import (
  "context"
  "log"

  rewrite "github.com/rewritetoday/golang"
)

func main() {
  client, err := rewrite.New("rw_your_api_key")
  if err != nil { log.Fatal(err) }

projectID := "748395130237498368"
firstNameFallback := "customer"
orderIDFallback := "0000"

_, err = client.Templates.Create(context.Background(), rewrite.CreateTemplateOptions{
  Project: projectID,
  RESTPostCreateTemplateBody: rewrite.RESTPostCreateTemplateBody{
    Name:    "order_shipped",
    Content: "Hi {{first_name}}, your order {{order_id}} is on the way.",
    Variables: []rewrite.APITemplateVariable{
      {Name: "first_name", Fallback: &firstNameFallback},
      {Name: "order_id", Fallback: &orderIDFallback},
    },
  },
})
if err != nil { log.Fatal(err) }
}

import com.rewritetoday.sdk.Rewrite;
import com.rewritetoday.sdk.models.templates.CreateTemplateOptions;
import com.rewritetoday.sdk.models.templates.TemplateVariable;
import java.util.List;

public class Main {
  public static void main(String[] args) throws Exception {
    var rewrite = new Rewrite(System.getenv("REWRITE_API_KEY"));

    var projectId = "748395130237498368";

    var template = rewrite.templates().create(
      CreateTemplateOptions.builder()
        .project(projectId)
        .name("order_shipped")
        .content("Hi {{first_name}}, your order {{order_id}} is on the way.")
        .variables(List.of(
          TemplateVariable.builder().name("first_name").fallback("customer").build(),
          TemplateVariable.builder().name("order_id").fallback("0000").build()
        ))
        .build()
    );

    System.out.println(template);
  }
}

